class Solution:
    def rangeSum(self, nums, n, left, right):
        MOD = 10 ** 9 + 7
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        sums = []
        for i in range(n):
            for j in range(i + 1, n + 1):
                sums.append(prefix[j] - prefix[i])
        sums.sort()
        total = 0
        for k in range(left - 1, right):
            total += sums[k]
        return total % MOD

