var rangeSum = function(nums, n, left, right) {
    const MOD = 1000000007;
    const sums = [];
    for (let i = 0; i < n; i++) {
        let s = 0;
        for (let j = i; j < n; j++) {
            s += nums[j];
            sums.push(s);
        }
    }
    sums.sort((a, b) => a - b);
    let total = 0;
    for (let k = left - 1; k < right; k++) total += sums[k];
    return total % MOD;
};
